+    /// `Object.defineProperties(O, props)` — define multiple properties.
+    pub fn define_properties(
+        &mut self,
+        handle: ObjectHandle,
+        props: Vec<(PropertyKey, PropertyDescriptor)>,
+    ) -> Result<bool, ObjectError> {
+        for (key, desc) in props {
